// ============================================================
// NODO: Build Email HTML (ACTUALIZADO)
// - Subject personalizado con nombre
// - Copy mejorado (emocional, no burocrático)
// - Botón CTA "Quiero más información" → mailto
// - Tracking pixel preparado (activar cuando tengas endpoint)
// ============================================================

const lead = $('Pick 1 Lead').item.json;

const supportedLangs = ['Español', 'Francés', 'Inglés', 'Italiano'];
let lang = supportedLangs.includes(lead.language) ? lead.language : 'Inglés';
const firstName = lead.first_name || lead.full_name || 'Student';
const titling = (lead.titling || lead.tipo_producto || 'tu programa')
  .replace(/^-\s*/, '').replace(/\s*-$/, '').replace(/\.\s*$/, '').trim();

const idempotencyKey = `cold_email:${lead.id}`;

// ── Mailto pre-rellenado por idioma (subject + body) ──
const country = lead.country || '___';

const mailtoSubjects = {
  'Español': `Solicitud de información - Homologación para ${titling}`,
  'Inglés': `Information request - Homologation for ${titling}`,
  'Francés': `Demande d'information - Homologation pour ${titling}`,
  'Italiano': `Richiesta informazioni - Omologazione per ${titling}`
};

const mailtoBodies = {
  'Español': `Hola,\n\nSoy ${firstName} y estoy interesado/a en recibir más información sobre el proceso de homologación para ${titling} en la Universidad Europea.\n\nMis estudios previos son del país: ${country}\nCarrera/título obtenido: [completar aquí]\n\nQuedo a la espera de su respuesta.\n\nSaludos,\n${firstName}`,
  'Inglés': `Hello,\n\nMy name is ${firstName} and I'm interested in receiving more information about the homologation process for ${titling} at Universidad Europea.\n\nMy previous studies are from: ${country}\nDegree obtained: [please complete here]\n\nLooking forward to your reply.\n\nBest regards,\n${firstName}`,
  'Francés': `Bonjour,\n\nJe suis ${firstName} et je souhaite recevoir plus d'informations sur le processus d'homologation pour ${titling} à l'Universidad Europea.\n\nMes études précédentes viennent du pays : ${country}\nDiplôme obtenu : [à compléter ici]\n\nDans l'attente de votre réponse.\n\nCordialement,\n${firstName}`,
  'Italiano': `Ciao,\n\nSono ${firstName} e sono interessato/a a ricevere maggiori informazioni sul processo di omologazione per ${titling} all'Universidad Europea.\n\nI miei studi precedenti sono del paese: ${country}\nTitolo ottenuto: [completare qui]\n\nIn attesa di una vostra risposta.\n\nCordiali saluti,\n${firstName}`
};

const mailtoHref = `mailto:center@spaceforedu.com?subject=${encodeURIComponent(mailtoSubjects[lang])}&body=${encodeURIComponent(mailtoBodies[lang])}`;

// ── Botón CTA ──
const ctaLabels = {
  'Español': 'Quiero más información',
  'Inglés': 'I want more information',
  'Francés': 'Je veux en savoir plus',
  'Italiano': 'Voglio saperne di più'
};

const ctaButton = `<table role="presentation" cellspacing="0" cellpadding="0" border="0" align="center" style="margin:24px auto 20px auto"><tr><td style="border-radius:8px;background:#0b69ff"><a href="${mailtoHref}" target="_blank" style="display:inline-block;padding:14px 36px;font-size:16px;font-weight:700;color:#ffffff;text-decoration:none;border-radius:8px;font-family:Segoe UI,Roboto,Helvetica,Arial,sans-serif">${ctaLabels[lang]}</a></td></tr></table>`;

// ── TRACKING PIXEL (activar cuando tengas endpoint) ──
// Reemplaza YOUR_TRACKING_URL por tu endpoint real.
// Ejemplo con n8n webhook: https://tu-n8n.com/webhook/track-open?lid={{lead.id}}
// Ejemplo con servidor propio: https://spaceforedu.com/track/open?lid={{lead.id}}
const TRACKING_ENABLED = false;
const trackingUrl = `https://YOUR_TRACKING_URL/track?lid=${lead.id}&t=${Date.now()}`;
const trackingPixel = TRACKING_ENABLED
  ? `<img src="${trackingUrl}" width="1" height="1" alt="" style="display:block;width:1px;height:1px;border:0;overflow:hidden" />`
  : '';

// ── Templates por idioma ──
const templates = {
  'Español': {
    subject: `${firstName}, solo falta un paso para empezar tu ${titling}`,
    greeting: `Hola ${firstName},`,
    body: `<p style="margin:0 0 14px 0;font-size:16px;line-height:1.6"><strong>¡Enhorabuena por tu admisión</strong> al programa de <strong>${titling}</strong> en la Universidad Europea! 🎉</p>
<p style="margin:0 0 14px 0;font-size:16px;line-height:1.6">Sabemos que este momento es muy especial para ti. Y queremos que empieces con buen pie: <strong>nosotros nos encargamos de toda la gestión de tu homologación</strong> para que tú solo te preocupes de disfrutar esta nueva etapa.</p>
<p style="margin:0 0 14px 0;font-size:16px;line-height:1.6">En <em>Space for Edu</em> ya hemos acompañado a cientos de estudiantes internacionales como tú. Nuestro equipo se ocupa de:</p>
<ul style="margin:0 0 14px 22px;padding:0;font-size:16px;line-height:1.8"><li style="margin:0 0 4px 0">Revisar y preparar toda tu documentación.</li><li style="margin:0 0 4px 0">Presentarla ante el organismo correspondiente.</li><li style="margin:0 0 4px 0">Mantenerte informado en cada paso del proceso.</li></ul>
<p style="margin:0 0 6px 0;font-size:16px;line-height:1.6"><strong>¿Tienes dudas? Escríbenos y te respondemos en menos de 24 horas:</strong></p>
${ctaButton}
<p style="margin:0 0 14px 0;font-size:14px;line-height:1.6;color:#555;text-align:center">O si lo prefieres, escríbenos por WhatsApp al <a href="https://wa.me/34635527594?text=${encodeURIComponent(`Hola, soy ${firstName} y quiero información sobre la homologación para ${titling}`)}" style="color:#0b69ff;text-decoration:none">+34 635 52 75 94</a></p>`,
    closing: `<p style="margin:20px 0 2px 0;font-size:16px;line-height:1.6">Un abrazo,</p>`,
    disclaimer: `De conformidad con la Ley Orgánica 3/2018 y el Reglamento (UE) 2016/679, los datos personales serán tratados por ROSFORD SL con la finalidad de posibilitar las comunicaciones. Puede ejercer sus derechos escribiendo a <a href="mailto:center@spaceforedu.com" style="color:#0b69ff;text-decoration:none">center@spaceforedu.com</a> o a CALLE BAHIA DE ALICANTE 82 PISO 1 D (28042) MADRID. Reclamaciones: <a href="https://www.aepd.es" style="color:#0b69ff;text-decoration:none">www.aepd.es</a>.`
  },
  'Inglés': {
    subject: `${firstName}, just one step left to start your ${titling}`,
    greeting: `Dear ${firstName},`,
    body: `<p style="margin:0 0 14px 0;font-size:16px;line-height:1.6"><strong>Congratulations on your admission</strong> to the <strong>${titling}</strong> program at Universidad Europea! 🎉</p>
<p style="margin:0 0 14px 0;font-size:16px;line-height:1.6">We know how exciting this moment is. And we want to make it easy: <strong>we handle your entire homologation process</strong> so you can focus on what really matters — your studies.</p>
<p style="margin:0 0 14px 0;font-size:16px;line-height:1.6">At <em>Space for Edu</em>, we've helped hundreds of international students just like you. Our team takes care of:</p>
<ul style="margin:0 0 14px 22px;padding:0;font-size:16px;line-height:1.8"><li style="margin:0 0 4px 0">Reviewing and preparing all your documentation.</li><li style="margin:0 0 4px 0">Submitting it to the relevant authority.</li><li style="margin:0 0 4px 0">Keeping you updated at every step.</li></ul>
<p style="margin:0 0 6px 0;font-size:16px;line-height:1.6"><strong>Have questions? Write to us and we'll reply within 24 hours:</strong></p>
${ctaButton}
<p style="margin:0 0 14px 0;font-size:14px;line-height:1.6;color:#555;text-align:center">Or if you prefer, message us on WhatsApp at <a href="https://wa.me/34635527594?text=${encodeURIComponent(`Hi, I'm ${firstName} and I want information about the homologation for ${titling}`)}" style="color:#0b69ff;text-decoration:none">+34 635 52 75 94</a></p>`,
    closing: `<p style="margin:20px 0 2px 0;font-size:16px;line-height:1.6">Best regards,</p>`,
    disclaimer: `In accordance with Organic Law 3/2018 and Regulation (EU) 2016/679, personal data will be processed by ROSFORD SL. Exercise your rights at <a href="mailto:center@spaceforedu.com" style="color:#0b69ff;text-decoration:none">center@spaceforedu.com</a>. Claims: <a href="https://www.aepd.es" style="color:#0b69ff;text-decoration:none">www.aepd.es</a>.`
  },
  'Francés': {
    subject: `${firstName}, plus qu'une étape pour commencer ton ${titling}`,
    greeting: `Bonjour ${firstName},`,
    body: `<p style="margin:0 0 14px 0;font-size:16px;line-height:1.6"><strong>Félicitations pour ton admission</strong> au programme <strong>${titling}</strong> à l'Universidad Europea ! 🎉</p>
<p style="margin:0 0 14px 0;font-size:16px;line-height:1.6">Nous savons à quel point ce moment est important. Et nous voulons te faciliter la tâche : <strong>nous nous chargeons de toute la gestion de ton homologation</strong> pour que tu puisses te concentrer sur tes études.</p>
<p style="margin:0 0 14px 0;font-size:16px;line-height:1.6">Chez <em>Space for Edu</em>, nous avons accompagné des centaines d'étudiants internationaux. Notre équipe s'occupe de :</p>
<ul style="margin:0 0 14px 22px;padding:0;font-size:16px;line-height:1.8"><li style="margin:0 0 4px 0">Vérifier et préparer tous tes documents.</li><li style="margin:0 0 4px 0">Les soumettre à l'organisme compétent.</li><li style="margin:0 0 4px 0">Te tenir informé à chaque étape.</li></ul>
<p style="margin:0 0 6px 0;font-size:16px;line-height:1.6"><strong>Des questions ? Écris-nous et nous te répondons en moins de 24 heures :</strong></p>
${ctaButton}
<p style="margin:0 0 14px 0;font-size:14px;line-height:1.6;color:#555;text-align:center">Ou si tu préfères, écris-nous sur WhatsApp au <a href="https://wa.me/34635527594?text=${encodeURIComponent(`Bonjour, je suis ${firstName} et je souhaite des informations sur l'homologation pour ${titling}`)}" style="color:#0b69ff;text-decoration:none">+34 635 52 75 94</a></p>`,
    closing: `<p style="margin:20px 0 2px 0;font-size:16px;line-height:1.6">Cordialement,</p>`,
    disclaimer: `Conformément à la Loi Organique 3/2018 et au Règlement (UE) 2016/679, les données personnelles seront traitées par ROSFORD SL. Droits : <a href="mailto:center@spaceforedu.com" style="color:#0b69ff;text-decoration:none">center@spaceforedu.com</a>. Réclamations : <a href="https://www.aepd.es" style="color:#0b69ff;text-decoration:none">www.aepd.es</a>.`
  },
  'Italiano': {
    subject: `${firstName}, manca solo un passo per iniziare il tuo ${titling}`,
    greeting: `Ciao ${firstName},`,
    body: `<p style="margin:0 0 14px 0;font-size:16px;line-height:1.6"><strong>Complimenti per la tua ammissione</strong> al programma <strong>${titling}</strong> all'Universidad Europea! 🎉</p>
<p style="margin:0 0 14px 0;font-size:16px;line-height:1.6">Sappiamo quanto sia importante questo momento. E vogliamo renderlo semplice: <strong>ci occupiamo noi di tutta la gestione della tua omologazione</strong> così tu puoi concentrarti su ciò che conta davvero — i tuoi studi.</p>
<p style="margin:0 0 14px 0;font-size:16px;line-height:1.6">A <em>Space for Edu</em> abbiamo già accompagnato centinaia di studenti internazionali come te. Il nostro team si occupa di:</p>
<ul style="margin:0 0 14px 22px;padding:0;font-size:16px;line-height:1.8"><li style="margin:0 0 4px 0">Verificare e preparare tutta la tua documentazione.</li><li style="margin:0 0 4px 0">Presentarla all'organismo competente.</li><li style="margin:0 0 4px 0">Tenerti aggiornato ad ogni passo.</li></ul>
<p style="margin:0 0 6px 0;font-size:16px;line-height:1.6"><strong>Hai domande? Scrivici e ti rispondiamo entro 24 ore:</strong></p>
${ctaButton}
<p style="margin:0 0 14px 0;font-size:14px;line-height:1.6;color:#555;text-align:center">Oppure scrivici su WhatsApp al <a href="https://wa.me/34635527594?text=${encodeURIComponent(`Ciao, sono ${firstName} e vorrei informazioni sull'omologazione per ${titling}`)}" style="color:#0b69ff;text-decoration:none">+34 635 52 75 94</a></p>`,
    closing: `<p style="margin:20px 0 2px 0;font-size:16px;line-height:1.6">Cordiali saluti,</p>`,
    disclaimer: `Ai sensi della Legge Organica 3/2018 e del Regolamento (UE) 2016/679, i dati personali saranno trattati da ROSFORD SL. Diritti: <a href="mailto:center@spaceforedu.com" style="color:#0b69ff;text-decoration:none">center@spaceforedu.com</a>. Reclami: <a href="https://www.aepd.es" style="color:#0b69ff;text-decoration:none">www.aepd.es</a>.`
  }
};

const t = templates[lang];
const langCode = lang === 'Español' ? 'es' : lang === 'Francés' ? 'fr' : lang === 'Italiano' ? 'it' : 'en';

const bodyHtml = `<!doctype html>
<html lang="${langCode}">
<head>
  <meta charset="utf-8">
  <meta name="x-apple-disable-message-reformatting">
  <meta name="format-detection" content="telephone=no, date=no, address=no, email=no">
</head>
<body style="margin:0;padding:0;background:#f5f7fa">
<center style="width:100%;background:#f5f7fa">
  <table role="presentation" cellspacing="0" cellpadding="0" border="0" align="center" width="100%" style="max-width:600px;margin:0 auto;background:#ffffff">
    <!-- CUERPO -->
    <tr>
      <td style="padding:28px;font-family:Segoe UI,Roboto,Helvetica,Arial,sans-serif;color:#111">
        <p style="margin:0 0 14px 0;font-size:16px;line-height:1.5">${t.greeting}</p>
        ${t.body}
        ${t.closing}
      </td>
    </tr>
    <!-- FIRMA -->
    <tr>
      <td style="padding:0 28px 24px 28px;font-family:Segoe UI,Roboto,Helvetica,Arial,sans-serif">
        <table role="presentation" cellspacing="0" cellpadding="0" border="0" width="100%">
          <tr>
            <td style="width:200px;vertical-align:top;padding-right:20px">
              <img src="https://spaceforedu.com/assets/SFE_Small_logo.jpg" alt="Space for Edu" width="160" style="display:block;border:0">
            </td>
            <td style="vertical-align:top">
              <table role="presentation" cellspacing="0" cellpadding="0" border="0" width="100%" style="border:1px solid #e6e8eb;border-radius:12px">
                <tr>
                  <td style="padding:16px 20px">
                    <p style="margin:0;font-size:18px;line-height:1.4;font-weight:700;color:#111">Matvey Sinelnik</p>
                    <p style="margin:2px 0 10px 0;font-size:14px;color:#555;line-height:1.4">Director — Rosford SL</p>
                    <p style="margin:0;font-size:14px;color:#111;line-height:1.7">📞 <a href="tel:+34635527594" style="color:#0b69ff;text-decoration:none">(+34) 635 52 75 94</a><br>✉️ <a href="mailto:center@spaceforedu.com" style="color:#0b69ff;text-decoration:none">center@spaceforedu.com</a><br>🌐 <a href="https://www.spaceforedu.com" style="color:#0b69ff;text-decoration:none">www.spaceforedu.com</a></p>
                  </td>
                </tr>
              </table>
            </td>
          </tr>
        </table>
      </td>
    </tr>
    <!-- LEGAL + TRACKING PIXEL -->
    <tr>
      <td style="padding:0 28px 28px 28px;font-family:Segoe UI,Roboto,Helvetica,Arial,sans-serif">
        <p style="margin:0;font-size:12px;line-height:1.6;color:#6b7280">${t.disclaimer}</p>
        ${trackingPixel}
      </td>
    </tr>
  </table>
</center>
</body>
</html>`;

const bodyText = bodyHtml.replace(/<[^>]+>/g, '').replace(/\s+/g, ' ').trim();

return [{
  json: {
    lead_id: lead.id,
    email: lead.email,
    first_name: firstName,
    language: lang,
    subject: t.subject,
    body_html: bodyHtml,
    body_text: bodyText,
    idempotency_key: idempotencyKey
  }
}];

parameters.query:
UPDATE leads SET email_status = 'failed', updated_at = NOW() WHERE id = $1;

UPDATE email_messages SET status = 'failed', error_message = 'Max retries exceeded', updated_at = NOW()
WHERE lead_id = $1 AND campaign_type = 'cold_email';

INSERT INTO email_events(email_message_id, lead_id, event_type, detail)
  SELECT id, $1, 'max_retries', '{}'::jsonb
  FROM email_messages WHERE lead_id = $1 AND campaign_type = 'cold_email';

-- Mark message sent
UPDATE email_messages SET status = 'sent', sent_at = NOW(), updated_at = NOW() WHERE id = $1;

-- Mark lead sent
UPDATE leads SET email_status = 'sent', last_email_sent_at = NOW(), updated_at = NOW() WHERE id = $2;

-- Heartbeat
UPDATE worker_locks SET heartbeat_at = NOW() WHERE lock_key = 'cold_email_worker' AND owner_id = $3;

-- Audit
INSERT INTO email_events(email_message_id, lead_id, event_type, detail) VALUES ($1, $2, 'sent', '{}'::jsonb);

UPDATE worker_locks SET heartbeat_at = NOW()
WHERE lock_key = 'cold_email_worker'
  AND owner_id = $1;

-- Reset completo para re-testear
DELETE FROM email_events
WHERE lead_id IN (SELECT id FROM leads WHERE email = 'matveysinelnik@gmail.com');

DELETE FROM email_messages
WHERE lead_id IN (SELECT id FROM leads WHERE email = 'matveysinelnik@gmail.com');

UPDATE leads
SET email_status = 'queued',
    last_email_sent_at = NULL,
    updated_at = NOW()
WHERE email = 'matveysinelnik@gmail.com';

DELETE FROM worker_locks
WHERE lock_key = 'cold_email_worker';
